import{_ as a,c as e,o as m,f as t}from"./plugin-vue_export-helper.ecc8ebe5.js";const q='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 17-18","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 17-18","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-01T00:00:00.000Z"},"relativePath":"texts/shiva-sutra-vimarshini/3/17-18.md","lastUpdated":1626205266596}',o={},i=t('<div class="stanza"><a href="#s3.17" id="s3.17" class="num">3.17</a><div class="sans"><p>\u0924\u0926\u0947\u0935\u0902 \u0928\u093E\u0921\u0940\u0938\u0902\u0939\u093E\u0930\u093E\u0926\u094D\u092F\u093E\u0923\u0935\u094B\u092A\u093E\u092F\u0915\u094D\u0930\u092E\u093E\u0938\u093E\u0926\u093F\u0924\u092E\u094B\u0939\u091C\u092F\u094B\u0928\u094D\u092E\u091C\u094D\u091C\u091A\u094D\u091B\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u0936\u093E\u0915\u094D\u0924\u092C\u0932\u093E\u0938\u093E\u0926\u0928\u092A\u094D\u0930\u0915\u0930\u094D\u0937\u093E\u0926\u093E\u0924\u094D\u092E\u0940\u0915\u0943\u0924\u092A\u0930\u093E\u092E\u0943\u0924\u0939\u094D\u0930\u0926\u093E\u0924\u094D\u092E\u0915\u0936\u093E\u092E\u094D\u092D\u0935\u092A\u0926\u094B \u092F\u094B\u0917\u0940\u2014</p><blockquote><p><strong>\u0938\u094D\u0935\u092E\u093E\u0924\u094D\u0930\u093E\u0928\u093F\u0930\u094D\u092E\u093E\u0923\u092E\u093E\u092A\u093E\u0926\u092F\u0924\u093F\u0965\u0967\u096D\u0965</strong></p></blockquote><p>\u0938\u094D\u0935\u0938\u094D\u092F \u091A\u0948\u0924\u0928\u094D\u092F\u0938\u094D\u092F \u0938\u092E\u094D\u092C\u0928\u094D\u0927\u093F\u0928\u0940 \u092E\u093E\u0924\u094D\u0930\u093E \u091A\u093F\u0926\u094D\u0930\u0938\u093E\u0936\u094D\u092F\u093E\u0928\u0924\u093E\u0924\u094D\u092E\u093E\u0902\u0936\u0938\u094D\u0924\u0926\u094D\u0930\u0942\u092A\u0902 \u092F\u0925\u0947\u0937\u094D\u091F\u0935\u0947\u0926\u094D\u092F\u0935\u0947\u0926\u0915\u093E\u0935\u092D\u093E\u0938\u093E\u0924\u094D\u092E\u0915\u0902 \u0928\u093F\u0930\u094D\u092E\u093E\u0923\u092E\u093E\u092A\u093E\u0926\u092F\u0924\u093F \u0928\u093F\u0930\u094D\u092E\u093F\u0924\u0924\u094D\u0935\u0947\u0928 \u0926\u0930\u094D\u0936\u092F\u0924\u093F\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0924\u0926\u0947\u0935 \u092D\u0935\u0924\u093F \u0938\u094D\u0925\u0942\u0932\u0902 \u0938\u094D\u0925\u0942\u0932\u094B\u092A\u093E\u0927\u093F\u0935\u0936\u093E\u0924\u094D\u092A\u094D\u0930\u093F\u092F\u0947\u0964<br> \u0938\u094D\u0925\u0942\u0932\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u0935\u093F\u092D\u0947\u0926\u0947\u0928 \u0924\u0926\u0947\u0915\u0902 \u0938\u0902\u0935\u094D\u092F\u0935\u0938\u094D\u0925\u093F\u0924\u092E\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u092F\u093E\u092E\u092A\u093F</p><blockquote><p>\u0906\u0924\u094D\u092E\u093E\u0928\u092E\u0924 \u090F\u0935\u093E\u092F\u0902 \u091C\u094D\u091E\u0947\u092F\u0940\u0915\u0941\u0930\u094D\u092F\u093E\u0924\u094D\u092A\u0943\u0925\u0915\u094D\u0938\u094D\u0925\u093F\u0924\u093F\u0964<br> \u091C\u094D\u091E\u0947\u092F\u0902 \u0928 \u0924\u0941...\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0906\u0917\u092E\u0947\u093D\u092A\u093F</p><blockquote><p>\u091C\u0932\u0902 \u0939\u093F\u092E\u0902 \u091A \u092F\u094B \u0935\u0947\u0926 \u0917\u0941\u0930\u0941\u0935\u0915\u094D\u0924\u094D\u0930\u093E\u0917\u092E\u093E\u0924\u094D\u092A\u094D\u0930\u093F\u092F\u0947\u0964<br> \u0928\u093E\u0938\u094D\u0924\u094D\u092F\u0947\u0935 \u0924\u0938\u094D\u092F \u0915\u0930\u094D\u0924\u0935\u094D\u092F\u0902 \u0924\u0938\u094D\u092F\u093E\u092A\u0936\u094D\u091A\u093F\u092E\u091C\u0928\u094D\u092E\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u0948\u0935\u093E\u0936\u092F\u0947\u0928\u094B\u0915\u094D\u0924\u092E\u094D\u0964 \u090F\u0924\u0926\u0947\u0935</p><blockquote><p>\u0907\u0924\u093F \u0935\u093E \u092F\u0938\u094D\u092F \u0938\u0902\u0935\u093F\u0924\u094D\u0924\u093F\u0903 \u0915\u094D\u0930\u0940\u0921\u093E\u0924\u094D\u0935\u0947\u0928\u093E\u0916\u093F\u0932\u0902 \u091C\u0917\u0924\u094D\u0964<br> \u0938 \u092A\u0936\u094D\u092F\u0928\u094D\u0938\u0924\u0924\u0902 \u092F\u0941\u0915\u094D\u0924\u094B \u091C\u0940\u0935\u0928\u094D\u092E\u0941\u0915\u094D\u0924\u094B \u0928 \u0938\u0902\u0936\u092F\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u093F\u0924\u092E\u094D\u0965\u0967\u096D\u0965</p></div><hr><div class="trans"><p>Tadeva\u1E41 n\u0101\u1E0D\u012Bsa\u1E41h\u0101r\u0101dy\u0101\u1E47avop\u0101yakram\u0101s\u0101ditamohajayonmajjacchuddhavidy\u0101tmaka\u015B\u0101ktabal\u0101s\u0101danaprakar\u1E63\u0101d\u0101tm\u012Bk\u1E5Btapar\u0101m\u1E5Btahrad\u0101tmaka\u015B\u0101mbhavapado yog\u012B\u2014</p><blockquote><p><strong>Svam\u0101tr\u0101nirm\u0101\u1E47am\u0101p\u0101dayati||17||</strong></p></blockquote><p>Svasya caitanyasya sambandhin\u012B m\u0101tr\u0101 cidras\u0101\u015By\u0101nat\u0101tm\u0101\u1E41\u015Bastadr\u016Bpa\u1E41 yathe\u1E63\u1E6Davedyavedak\u0101vabh\u0101s\u0101tmaka\u1E41 nirm\u0101\u1E47am\u0101p\u0101dayati nirmitatvena dar\u015Bayati| Yadukta\u1E41 \u015Br\u012Bsvacchande</p><blockquote><p>Tadeva bhavati sth\u016Bla\u1E41 sth\u016Blop\u0101dhiva\u015B\u0101tpriye|<br> Sth\u016Blas\u016Bk\u1E63mavibhedena tadeka\u1E41 sa\u1E41vyavasthitam||</p></blockquote><p>iti| Pratyabhij\xF1\u0101y\u0101mapi</p><blockquote><p>\u0100tm\u0101namata ev\u0101ya\u1E41 j\xF1ey\u012Bkury\u0101tp\u1E5Bthaksthiti|<br> J\xF1eya\u1E41 na tu...||</p></blockquote><p>iti| \u0100game&#39;pi</p><blockquote><p>Jala\u1E41 hima\u1E41 ca yo veda guruvaktr\u0101gam\u0101tpriye|<br> N\u0101styeva tasya kartavya\u1E41 tasy\u0101pa\u015Bcimajanmat\u0101||</p></blockquote><p>ityanenaiv\u0101\u015Bayenoktam| Etadeva</p><blockquote><p>Iti v\u0101 yasya sa\u1E41vitti\u1E25 kr\u012B\u1E0D\u0101tven\u0101khila\u1E41 jagat|<br> Sa pa\u015Byansatata\u1E41 yukto j\u012Bvanmukto na sa\u1E41\u015Baya\u1E25||</p></blockquote><p>ityanena spande pratip\u0101ditam||17||</p></div><hr><p>\u042D\u0442\u043E <em>(tad)</em> [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E] \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u0435\u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0438 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0441\u0442\u0432\u043E <em>(prakar\u1E63\u0101t)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u044B\u0435 <em>(\u0101s\u0101dana)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u0438\u043B\u044B <em>(bala)</em> \u015Aakti <em>(\u015B\u0101kta)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 <em>(\u0101tmaka)</em> \u015Auddhavidy\u0101 --\u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F<sup>1</sup>-- <em>(\u015Buddha-vidy\u0101)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0435\u0433\u043E <em>(unmajjat)</em> \u0438\u0437 \u043F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u044F <em>(jaya)</em> Moha, \u0438\u043B\u0438 \u041D\u0430\u0432\u0430\u0436\u0434\u0435\u043D\u0438\u044F --M\u0101y\u0101-- <em>(moha)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F <em>(\u0101s\u0101dita)</em> \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(krama)</em> \u043C\u0435\u0442\u043E\u0434\u043E\u0432 <em>(up\u0101ya)</em> \u0432 \u0101\u1E47ava --\u0442.\u0435. \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A \u0100\u1E47avop\u0101ya-- <em>(\u0101\u1E47ava)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 [\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438] <em>(sa\u1E41h\u0101ra)</em> \u0432 \u0442\u043E\u043D\u043A\u0438\u0445 \u043A\u0430\u043D\u0430\u043B\u0430\u0445 <em>(n\u0101\u1E0D\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> --\u0421\u043C. III, 5--, Yog\u012B <em>(yog\u012B)</em> \u043E\u0432\u043B\u0430\u0434\u0435\u0432\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(\u0101tm\u012B-k\u1E5Bta... pada\u1E25)</em> \u015Aiva <em>(\u015B\u0101mbhava)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0435\u0441\u0442\u044C [\u043D\u0438\u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A] <em>(\u0101tmaka)</em> \u041E\u0437\u0435\u0440\u043E <em>(hrada)</em> \u0432\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u044F <em>(am\u1E5Bta)</em>\u2014</p><blockquote><p><strong>[\u042D\u0442\u043E\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0439 Yog\u012B \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D] \u0441\u043E\u0437\u0434\u0430\u0442\u044C <em>(nirm\u0101\u1E47am \u0101p\u0101dayati)</em> [\u043B\u044E\u0431\u0443\u044E \u0444\u043E\u0440\u043C\u0443, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E] \u043C\u0435\u0440\u0435, \u0438\u043B\u0438 \u0430\u0441\u043F\u0435\u043A\u0442\u0443 \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F [\u0441\u043B\u0443\u0436\u0430\u0449\u0435\u0433\u043E \u0435\u043C\u0443 &quot;\u0101sana&quot;, \u0438\u043B\u0438 &quot;\u0441\u0438\u0434\u0435\u043D\u044C\u0435\u043C&quot; --\u0441\u043C. 16<sup>\u044B\u0439</sup> \u0430\u0444\u043E\u0440\u0438\u0437\u043C--] <em>(svam\u0101tr\u0101)</em>||17||</strong></p></blockquote><p>[\u0422\u0435\u0440\u043C\u0438\u043D svam\u0101tr\u0101 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043C\u0435\u0440\u0443 <em>(m\u0101tr\u0101)</em>, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u0443\u044E \u0441 <em>(sambandhin\u012B)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(svasya)</em> [\u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C] \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(caitanyasya)</em>, [\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F,] \u0441 \u0430\u0441\u043F\u0435\u043A\u0442\u043E\u043C <em>(a\u1E41\u015Ba\u1E25)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(\u0101tm\u0101)</em> \u043A\u043E\u0430\u0433\u0443\u043B\u044F\u0446\u0438\u044F <em>(\u0101\u015By\u0101nat\u0101)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 <em>(rasa)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em><sup>2</sup>. \u0412 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u043C\u0435\u0440\u043E\u0439 \u044D\u0442\u043E\u0433\u043E [\u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(tad-r\u016Bpam)</em>, [\u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0439 Yog\u012B] \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442 <em>(\u0101p\u0101dayati)</em> \u043F\u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0443 <em>(nirm\u0101\u1E47am)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0438\u0437 <em>(\u0101tmakam)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(avabh\u0101sa)</em> \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0445 --\u0442.\u0435. \u0441\u0443\u0449\u0435\u0441\u0442\u0432-- <em>(vedaka)</em> [\u0438] \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0433\u043E --\u0442.\u0435. \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432-- <em>(vedya)</em> \u043A\u0430\u043A <em>(yath\u0101)</em> [\u043E\u043D] \u043F\u043E\u0436\u0435\u043B\u0430\u0435\u0442 <em>(i\u1E63\u1E6Da)</em>. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438,] \u043E\u043D \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 [\u0432\u0441\u0435 \u044D\u0442\u0438 \u0432\u0435\u0449\u0438] <em>(dar\u015Bayati)</em> \u043F\u0443\u0442\u0435\u043C [\u0438\u0445] \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 <em>(nirmitatvena)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>:</p><blockquote><p>&quot;\u041E, \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u0422\u043E\u0442 <em>(tad)</em><sup>3</sup> \u043E\u0434\u0438\u043D <em>(eva)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(bhavati)</em> \u043A\u0430\u043A \u0433\u0440\u0443\u0431\u043E\u0435 <em>(sth\u016Blam)</em> \u0438\u0437-\u0437\u0430 [\u0415\u0433\u043E] \u0436\u0435\u043B\u0430\u043D\u0438\u044F *(va\u015B\u0101t)*\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(up\u0101dhi)</em> \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0433\u0440\u0443\u0431\u044B\u043C <em>(sth\u016Bla)</em>. \u0422\u043E\u0442 <em>(tad)</em> \u043E\u0434\u0438\u043D <em>(ekam)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A <em>(sa\u1E41vyavasthitam)</em> \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u0435, \u0438\u043B\u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 <em>(vibhedena)</em> \u0433\u0440\u0443\u0431\u043E\u0433\u043E <em>(sth\u016Bla)</em> [\u0438] \u0442\u043E\u043D\u043A\u043E\u0433\u043E <em>(s\u016Bk\u1E63ma... iti)</em>&quot;||<br> [\u0421\u043C. IV, 295 \u0432 Svacchandatantra]</p></blockquote><p>\u0412 \u012A\u015Bvarapratyabhij\xF1\u0101 <em>(pratyabhij\xF1\u0101y\u0101m)</em> [\u044D\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E] <em>(api)</em>:</p><blockquote><p>&quot;\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 [Vimar\u015Ba\u015Bakti --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0441\u0438\u043B\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F--] <em>(atas eva)</em>, \u041E\u043D <em>(ayam)</em> \u0434\u0435\u043B\u0430\u0435\u0442 \u0441\u0435\u0431\u044F j\xF1eya, \u0438\u043B\u0438 \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u043C --\u0442.\u0435. \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C-- <em>(\u0101tm\u0101nam... j\xF1ey\u012B-kury\u0101t)</em>. \u041F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435 <em>(j\xF1eyam)</em> \u043D\u0435 <em>(na tu)</em> \u0438\u043C\u0435\u0435\u0442 \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(p\u1E5Bthak-sthiti... iti)</em>. [\u0415\u0441\u043B\u0438 \u0431\u044B [\u041E\u043D] \u0431\u044B\u043B \u0437\u0430\u0432\u0438\u0441\u0438\u043C --\u0431\u0443\u043A\u0432. \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C \u0441-- \u043E\u0442 \u044D\u0442\u043E\u0433\u043E [\u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0433\u043E], \u0442\u043E \u0415\u0433\u043E \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0430\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u0430 \u0431\u044B\u043B\u0430 \u0431\u044B \u043D\u0430\u0440\u0443\u0448\u0435\u043D\u0430]<sup>4</sup>&quot;|<br> [\u0421\u043C. I, 5, 15 \u0432 \u012A\u015Bvarapratyabhij\xF1\u0101]</p></blockquote><p>\u0412 \u0100gama --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u043C \u041F\u0438\u0441\u0430\u043D\u0438\u0438-- <em>(\u0101game)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em>, \u0441\u043A\u0430\u0437\u0430\u043D\u043E [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435] <em>(uktam)</em> \u0441 \u0442\u0435\u043C \u0436\u0435 \u0441\u0430\u043C\u044B\u043C \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435\u043C <em>(anena eva \u0101\u015Bayena)</em>:</p><blockquote><p>&quot;\u041E, \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u0442\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0437\u043D\u0430\u0435\u0442 <em>(veda)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0438\u0437 <em>(\u0101gam\u0101t)</em> \u0443\u0441\u0442 <em>(vaktra)</em> [\u0435\u0433\u043E] \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0430 <em>(guru)</em>, \u0447\u0442\u043E \u0432\u043E\u0434\u0430 <em>(jalam)</em> \u0438 <em>(ca)</em> \u043B\u0435\u0434 <em>(himam)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0434\u043D\u043E\u0439 \u0438 \u0442\u043E\u0439 \u0436\u0435 \u0432\u0435\u0449\u044C\u044E, \u2014 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D]. \u0414\u043B\u044F \u043D\u0435\u0433\u043E <em>(tasya)</em> \u043D\u0435\u0442 \u043D\u0438\u0447\u0435\u0433\u043E, \u0447\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0441\u0434\u0435\u043B\u0430\u043D\u043E <em>(na asti eva... kartavyam)</em>. \u041E\u043D \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F <em>(tasya)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(apa\u015Bcima-janmat\u0101)</em> --\u0442.\u0435. \u043E\u043D \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u043D\u0438 \u0435\u0434\u0438\u043D\u043E\u0433\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0433\u043E \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0432 \u0446\u0435\u043B\u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0435\u043C\u0443 \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F Sa\u1E41s\u0101ra, \u0438\u043B\u0438 \u0422\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u044F--&quot;||</p></blockquote><p>\u042D\u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 [\u0443\u0447\u0435\u043D\u0438\u0435] <em>(etad)</em> \u0431\u044B\u043B\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u043E <em>(pratip\u0101ditam)</em> \u044D\u0442\u0438\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C] <em>(anena)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em>:</p><blockquote><p>&quot;\u0418\u043B\u0438 <em>(iti v\u0101)</em> \u0442\u043E\u0442 <em>(sa\u1E25)</em>, \u043A\u0442\u043E \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u044D\u0442\u0438\u043C <em>(yasya)</em> \u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(sa\u1E41vitti\u1E25)</em> [\u0438] \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(satatam)</em> \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 [\u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F] <em>(yukta\u1E25)</em>, \u0432\u0438\u0434\u0438\u0442 <em>(pa\u015Byan)</em> \u0432\u0435\u0441\u044C <em>(akhilam)</em> \u043C\u0438\u0440 <em>(jagat)</em>, \u043A\u0430\u043A [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E] \u0438\u0433\u0440\u0443 <em>(kr\u012B\u1E0D\u0101tvena)</em>. \u041E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438 <em>(j\u012Bvanmukta\u1E25)</em>, \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 <em>(na)</em> \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 <em>(sa\u1E41\u015Baya\u1E25... iti)</em> [\u0432 \u044D\u0442\u043E\u043C]&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s II, 5]</p></blockquote><p>||17||</p><hr><ol><li><p>\u042D\u0442\u043E \u0432\u043E\u0432\u0441\u0435 \u043D\u0435 \u043F\u044F\u0442\u0430\u044F \u0442\u0430\u0442\u0442\u0432\u0430, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F (\u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A Sadvidy\u0101). \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u2014 \u043D\u0435 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F. II, 10 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0437\u043E\u0431\u0440\u0430\u0442\u044C\u0441\u044F \u0441 \u044D\u0442\u0438\u043C.</p></li><li><p>\u0421\u043E\u0437\u0438\u0434\u0430\u043D\u0438\u0435 \u0432 \u0422\u0440\u0438\u043A\u0435 \u043D\u0435 \u043F\u043E\u0445\u043E\u0436\u0435 \u043D\u0430 \u0440\u0430\u0431\u043E\u0442\u0443 \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u0438\u043A\u0430, \u0442.\u0435. \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E, \u0441\u043E\u0437\u0434\u0430\u043D\u043D\u043E\u0435 \u043A\u0435\u043C-\u0442\u043E, \u043A\u0442\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043B \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0438 \u043D\u0430\u043A\u043E\u043D\u0435\u0446, \u0441\u043E\u0437\u0434\u0430\u043B \u0447\u0442\u043E-\u0442\u043E, \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0435 \u043E\u0442 \u043D\u0435\u0433\u043E \u0441\u0430\u043C\u043E\u0433\u043E. \u041D\u0435\u0442. \u0422\u043E\u043B\u044C\u043A\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 Caitanya \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0432\u0441\u0435\u043C \u0438 \u043A\u0430\u0436\u0434\u044B\u043C, \u0442.\u0435. \u041E\u043D\u043E \u043A\u043E\u0430\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u0442, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 \u0432\u0435\u0449\u0435\u0439 \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u043D\u0435 \u043F\u0440\u0438\u0431\u0435\u0433\u0430\u044F \u043D\u0438 \u043A \u0447\u0435\u043C\u0443 \u0434\u0440\u0443\u0433\u043E\u043C\u0443, \u043A\u0440\u043E\u043C\u0435 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0442\u0435\u0440\u043C\u0438\u043D &quot;\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435&quot; \u0431\u043E\u043B\u0435\u0435 \u0443\u043C\u0435\u0441\u0442\u0435\u043D, \u0438\u043B\u0438 \u043F\u0440\u0430\u0432\u0438\u043B\u0435\u043D, \u0447\u0435\u043C &quot;\u0441\u043E\u0437\u0438\u0434\u0430\u043D\u0438\u0435&quot;\u0432 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u0422\u0440\u0438\u043A\u0438.</p></li><li><p>\u0412 \u0441\u0432\u043E\u0435\u0439 Svacchandoddyota, K\u1E63emar\u0101ja \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u0442 &quot;\u0422\u043E\u0442&quot; \u043A\u0430\u043A &quot; \u092E\u0939\u093E\u092A\u094D\u0930\u0915\u093E\u0936\u093E\u0924\u094D\u092E\u093E \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u0928\u093E\u0925\u0903&quot; - &quot;Mah\u0101prak\u0101\u015B\u0101tm\u0101 \u015Br\u012Bsvatantran\u0101tha\u1E25&quot; - &quot;\u0414\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u044B\u0439 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u2014 \u0412\u0435\u043B\u0438\u043A\u0438\u0439 \u0421\u0432\u0435\u0442&quot;. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u041E\u043D \u2014 \u043D\u0438\u043A\u0442\u043E \u0438\u043D\u043E\u0439, \u043A\u0430\u043A Caitanya, \u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0432 \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u0435.</p></li><li><p>\u042F \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u043B \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u0432\u0441\u044E \u0441\u0442\u0440\u043E\u0444\u0443, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u043F\u043E\u043B\u043D\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435. \u041E\u0441\u0442\u0430\u0432\u0448\u0430\u044F\u0441\u044F \u0447\u0430\u0441\u0442\u044C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u043E\u0442\u0431\u0440\u043E\u0448\u0435\u043D\u0430 \u0438 \u043E\u0442\u043C\u0435\u0447\u0435\u043D\u0430 \u043C\u043D\u043E\u0433\u043E\u0442\u043E\u0447\u0438\u0435\u043C, \u044D\u0442\u043E: &quot; \u0924\u0926\u094C\u0928\u094D\u092E\u094D\u092F\u094D\u0916\u094D\u092F\u093E\u0924\u094D\u0916\u0923\u094D\u0921\u094D\u092F\u0947\u0924\u093E\u0938\u094D\u092F \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u0924\u093E\u0965\u0967\u096B\u0965 &quot; - &quot;tadaunmykhy\u0101tkha\u1E47\u1E0Dyet\u0101sya svatantrat\u0101||15||&quot;. \u042D\u0442\u043E\u0442 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0441\u0430\u043C\u043E\u043C \u0442\u0435\u043A\u0441\u0442\u0435 \u0432\u044B\u0448\u0435. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u044F \u0434\u043E\u0431\u0430\u0432\u0438\u043B \u0432 \u043C\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0442\u0435\u0440\u043C\u0438\u043D &quot;Vimar\u015Ba\u015Bakti&quot;. \u041F\u043E\u0447\u0435\u043C\u0443? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0434\u043E \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u044B\u0439 \u043C\u0443\u0434\u0440\u0435\u0446 Abhinavagupta (\u0413\u0443\u0440\u0443 \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0438) \u043F\u0440\u043E\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043B \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 (\u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438, \u043E\u043D \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u043F\u0440\u043E\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043B \u0441\u0442\u0440\u043E\u0444\u044B 15 \u0438 16) \u0432 \u0441\u0432\u043E\u0435\u0439 \u012A\u015Bvarapratyabhij\xF1\u0101vimar\u015Bin\u012B (\u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u043D\u0430\u0443\u0447\u043D\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043D\u0430 \u012A\u015Bvarapratyabhij\xF1\u0101 \u0423\u0442\u043F\u0430\u043B\u0430\u0434\u0435\u0432\u044B), \u043E\u043D \u0432\u044B\u0434\u0432\u0438\u043D\u0443\u043B \u0432\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044F \u0442\u0435\u0440\u043C\u0438\u043D Vimar\u015Ba\u015Bakti. \u0417\u0430\u0442\u0435\u043C, \u0441\u0442\u0440\u043E\u0444\u044B 15 \u0438 16, \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0440\u0430\u0441\u0441\u0435\u0438\u0432\u0430\u044E\u0442 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F, \u0432\u044B\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0435 \u0438\u043C. \u042D\u0442\u0438 \u0430\u0432\u0442\u043E\u0440\u044B (\u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A, Abhinavagupta, K\u1E63emar\u0101ja, \u0438 \u0434\u0440.) \u043E\u0431\u044B\u0447\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u043C\u0435\u0442\u043E\u0434 \u0432\u044B\u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u0432\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0439, \u0447\u0442\u043E\u0431\u044B \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0438\u0445 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u0431\u043E\u043B\u0435\u0435 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C\u0438 \u0438 \u0434\u0438\u0434\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 (\u0434\u0438\u0434\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0434\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0443\u0447\u0435\u043D\u044B\u0445, \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E, \u0445\u0430-\u0445\u0430!). \u041E\u041A, \u0442\u0435\u043F\u0435\u0440\u044C \u0432\u0441\u0435 \u043F\u043E\u043D\u044F\u0442\u043D\u043E. \u041F\u0440\u043E\u0441\u0442\u043E \u0434\u043E\u0432\u0435\u0440\u044F\u0439 \u043C\u043D\u0435, \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 \u0446\u0435\u043B\u043E\u043C, \u044F \u0447\u0438\u0442\u0430\u044E \u043C\u043D\u043E\u0433\u043E &quot;\u0431\u0435\u0437\u0443\u043C\u043D\u043E \u0434\u043B\u0438\u043D\u043D\u044B\u0445&quot; \u043F\u0438\u0441\u0430\u043D\u0438\u0439 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E, \u043F\u043E\u043A\u0430 \u043F\u0435\u0440\u0435\u0432\u043E\u0436\u0443 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435. \u0418\u043D\u043E\u0433\u0434\u0430 \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u0432\u0441\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E, \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0438\u043D\u0430\u0447\u0435 \u044D\u0442\u043E\u0442 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043F\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u0442\u0441\u044F \u0432 \u0446\u0435\u043B\u0443\u044E \u044D\u043D\u0446\u0438\u043A\u043B\u043E\u043F\u0435\u0434\u0438\u044E.</p></li></ol></div><div class="stanza"><a href="#s3.18" id="s3.18" class="num">3.18</a><div class="sans"><p>\u0928 \u091A\u0948\u0935\u0902 \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u0928\u093F\u0930\u094D\u092E\u093F\u0924\u092D\u0942\u0924\u092D\u093E\u0935\u0936\u0930\u0940\u0930\u0935\u0924\u094B\u093D\u0938\u094D\u092F \u091C\u0928\u094D\u092E\u093E\u0926\u093F\u092C\u0928\u094D\u0927\u0903 \u0915\u0936\u094D\u091A\u093F\u0926\u093F\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0935\u093F\u0926\u094D\u092F\u093E\u0935\u093F\u0928\u093E\u0936\u0947 \u091C\u0928\u094D\u092E\u0935\u093F\u0928\u093E\u0936\u0903\u0965\u0967\u096E\u0965</strong></p></blockquote><p>\u092A\u094D\u0930\u094B\u0915\u094D\u0924\u093E\u092F\u093E\u0903 \u0938\u0939\u091C\u0935\u093F\u0926\u094D\u092F\u093E\u092F\u093E \u0905\u0935\u093F\u0928\u093E\u0936\u0947 \u0938\u0924\u0924\u094B\u0928\u094D\u092E\u0917\u094D\u0928\u0924\u092F\u093E \u0938\u094D\u092B\u0941\u0930\u0923\u0947 \u091C\u0928\u094D\u092E\u0928\u094B\u093D\u091C\u094D\u091E\u093E\u0928\u0938\u0939\u0915\u093E\u0930\u093F\u0915\u0930\u094D\u092E\u0939\u0947\u0924\u0941\u0915\u0938\u094D\u092F \u0926\u0941\u0903\u0916\u092E\u092F\u0938\u094D\u092F \u0926\u0947\u0939\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0926\u093F\u0938\u092E\u0941\u0926\u093E\u092F\u0938\u094D\u092F \u0928\u093E\u0936\u094B \u0935\u093F\u0927\u094D\u0935\u0902\u0938\u0903 \u0938\u092E\u094D\u092A\u0928\u094D\u0928 \u090F\u0935\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0915\u0923\u094D\u0920\u094D\u092F\u093E\u092E\u094D</p><blockquote><p>\u0938\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0902 \u092A\u0930\u093F\u0924\u094D\u092F\u091C\u094D\u092F \u0939\u0947\u092F\u094B\u092A\u093E\u0926\u0947\u092F\u0932\u0915\u094D\u0937\u0923\u092E\u094D\u0964<br> \u0924\u0943\u0923\u093E\u0926\u093F\u0915\u0902 \u0924\u0925\u093E \u092A\u0930\u094D\u0923\u0902 \u092A\u093E\u0937\u093E\u0923\u0902 \u0938\u091A\u0930\u093E\u091A\u0930\u092E\u094D\u0965<br> \u0936\u093F\u0935\u093E\u0926\u094D\u092F\u0935\u0928\u093F\u092A\u0930\u094D\u092F\u0928\u094D\u0924\u0902 \u092D\u093E\u0935\u093E\u092D\u093E\u0935\u094B\u092A\u092C\u0943\u0902\u0939\u093F\u0924\u092E\u094D\u0964<br> \u0938\u0930\u094D\u0935\u0902 \u0936\u093F\u0935\u092E\u092F\u0902 \u0927\u094D\u092F\u093E\u0924\u094D\u0935\u093E \u092D\u0942\u092F\u094B \u091C\u0928\u094D\u092E \u0928 \u092A\u094D\u0930\u093E\u092A\u094D\u0928\u0941\u092F\u093E\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0938\u0941\u0928\u093F\u0930\u094D\u0935\u093E\u0923\u0902 \u092A\u0930\u0902 \u0936\u0941\u0926\u094D\u0927\u0902 \u0917\u0941\u0930\u0941\u092A\u093E\u0930\u092E\u094D\u092A\u0930\u093E\u0917\u0924\u092E\u094D\u0964<br> \u0924\u0926\u094D\u0935\u093F\u0926\u093F\u0924\u094D\u0935\u093E \u0935\u093F\u092E\u0941\u091A\u094D\u092F\u0947\u0924 \u0917\u0924\u094D\u0935\u093E \u092D\u0942\u092F\u094B \u0928 \u091C\u093E\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0924\u094D\u092F\u092A\u093F</p><blockquote><p>\u0924\u0924\u094D\u0924\u094D\u0935\u0924\u094D\u0930\u092F\u0935\u093F\u0928\u093F\u0930\u094D\u092E\u0941\u0915\u094D\u0924\u0902 \u0936\u093E\u0936\u094D\u0935\u0924\u0902 \u0924\u094D\u0935\u091A\u0932\u0902 \u0927\u094D\u0930\u0941\u0935\u092E\u094D\u0964<br> \u0926\u093F\u0935\u094D\u092F\u0947\u0928 \u092F\u094B\u0917\u092E\u093E\u0930\u094D\u0917\u0947\u0923 \u0926\u0943\u0937\u094D\u091F\u094D\u0935\u093E \u092D\u0942\u092F\u094B \u0928 \u091C\u093E\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0967\u096E\u0965</p></div><hr><div class="trans"><p>Na caiva\u1E41 sva\u015Baktinirmitabh\u016Btabh\u0101va\u015Bar\u012Bravato&#39;sya janm\u0101dibandha\u1E25 ka\u015Bcidity\u0101ha\u2014</p><blockquote><p><strong>Vidy\u0101vin\u0101\u015Be janmavin\u0101\u015Ba\u1E25||18||</strong></p></blockquote><p>Prokt\u0101y\u0101\u1E25 sahajavidy\u0101y\u0101 avin\u0101\u015Be satatonmagnatay\u0101 sphura\u1E47e janmano&#39;j\xF1\u0101nasahak\u0101rikarmahetukasya du\u1E25khamayasya dehendriy\u0101disamud\u0101yasya n\u0101\u015Bo vidhva\u1E41sa\u1E25 sampanna eva| Yadukta\u1E41 \u015Br\u012Bka\u1E47\u1E6Dhy\u0101m</p><blockquote><p>Saprapa\xF1ca\u1E41 parityajya heyop\u0101deyalak\u1E63a\u1E47am|<br> T\u1E5B\u1E47\u0101dika\u1E41 tath\u0101 par\u1E47a\u1E41 p\u0101\u1E63\u0101\u1E47a\u1E41 sacar\u0101caram||<br> \u015Aiv\u0101dyavaniparyanta\u1E41 bh\u0101v\u0101bh\u0101vopab\u1E5B\u1E41hitam|<br> Sarva\u1E41 \u015Bivamaya\u1E41 dhy\u0101tv\u0101 bh\u016Byo janma na pr\u0101pnuy\u0101t||</p></blockquote><p>iti| \u015Ar\u012Bsvacchande</p><blockquote><p>Sunirv\u0101\u1E47a\u1E41 para\u1E41 \u015Buddha\u1E41 gurup\u0101rampar\u0101gatam|<br> Tadviditv\u0101 vimucyeta gatv\u0101 bh\u016Byo na j\u0101yate||</p></blockquote><p>iti| \u015Ar\u012Bm\u1E5Btyujityapi</p><blockquote><p>Tattvatrayavinirmukta\u1E41 \u015B\u0101\u015Bvata\u1E41 tvacala\u1E41 dhruvam|<br> Divyena yogam\u0101rge\u1E47a d\u1E5B\u1E63\u1E6Dv\u0101 bh\u016Byo na j\u0101yate||</p></blockquote><p>iti||18||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na ca... ka\u015Bcid)</em> \u0440\u0430\u0431\u0441\u0442\u0432\u043E <em>(bandha\u1E25)</em> [\u0432 \u0444\u043E\u0440\u043C\u0435] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u043B \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bravata\u1E25)</em>, \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0435 <em>(nirmita)</em> \u0438\u0437 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0442.\u0435. \u0442\u0435\u043B\u043E-- \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 bh\u016Bta-s --\u0442.\u0435. Mah\u0101bh\u016Bta-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 (tattva-s 32 to 36)-- <em>(bh\u016Bta)</em> [\u0438] bh\u0101va-s --\u0442.\u0435. Tanm\u0101tra-s, \u0438\u043B\u0438 \u0422\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 (\u0442\u0430\u0442\u0442\u0432\u044B \u0441 27 \u043F\u043E 31), \u044D\u043C\u043E\u0446\u0438\u0439 \u0438 \u0442.\u0434.-- <em>(bh\u0101va)</em>. [\u0410\u0432\u0442\u043E\u0440 \u015Aivas\u016Btra-s, \u0442.\u0435. \u015Aiva,] \u0441\u043A\u0430\u0437\u0430\u043B \u0442\u0430\u043A <em>(iti \u0101ha)</em>\u2014</p><blockquote><p><strong>\u0414\u043E \u0442\u0435\u0445 \u043F\u043E\u0440 \u043F\u043E\u043A\u0430 Sahajavidy\u0101, \u0438\u043B\u0438 \u015Auddhavidy\u0101, [\u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435, \u0438\u043B\u0438 \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435] <em>(vidy\u0101)</em> \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(avin\u0101\u015Be)</em>, [\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0434\u0440\u0443\u0433\u043E\u0433\u043E] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em> \u0443\u0442\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F [\u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B] <em>(vin\u0101\u015Ba\u1E25)</em>||18||</strong></p></blockquote><p>\u0414\u043E \u0442\u0435\u0445 \u043F\u043E\u0440 \u043F\u043E\u043A\u0430 \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(avin\u0101\u015Be)</em> \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435 <em>(prokt\u0101y\u0101\u1E25)</em> \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 <em>(sahajavidy\u0101y\u0101\u1E25)</em>, \u0442.\u0435. \u043F\u043E\u043A\u0430 \u043E\u043D\u043E \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F <em>(sphura\u1E47e)</em> \u043A\u0430\u043A \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(unmagnatay\u0101)</em>, \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(n\u0101\u015Ba\u1E25)</em>, [\u0438\u043B\u0438] \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 <em>(vidhva\u1E41sa\u1E25)</em> [\u0434\u0440\u0443\u0433\u043E\u0433\u043E] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janmana\u1E25)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438 <em>(samud\u0101yasya)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em>, \u0447\u0443\u0432\u0441\u0442\u0432 <em>(indriya)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043F\u043E\u043B\u043D\u043E\u0433\u043E <em>(mayasya)</em> \u0431\u043E\u043B\u0438 <em>(du\u1E25kha)</em>, [\u0438] \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0433\u043E <em>(hetukasya)</em> [\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C\u0438 <em>(karma)</em> \u0432\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0438 \u0441 <em>(sahak\u0101ri)</em> \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C, [\u0438\u043B\u0438 M\u0101y\u0101 \u0438 \u0435\u0435 \u043F\u043E\u0442\u043E\u043C\u0441\u0442\u0432\u043E\u043C] <em>(aj\xF1\u0101na)</em>, \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(sampanna\u1E25)</em> \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(eva)</em><sup>1</sup>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Ka\u1E47\u1E6Dh\u012B <em>(\u015Br\u012B-ka\u1E47\u1E6Dhy\u0101m)</em>:</p><blockquote><p>&quot;\u041E\u0441\u0442\u0430\u0432\u0438\u0432 <em>(parityajya)</em> [\u043C\u0438\u0440] \u0441 [\u0435\u0433\u043E] \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u0430\u043C\u0438 <em>(sa-prapa\xF1cam)</em>, \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0438\u0441\u044F \u043A\u0430\u043A <em>(lak\u1E63a\u1E47am)</em> \u0447\u0442\u043E-\u043B\u0438\u0431\u043E \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0435 <em>(up\u0101deya)</em> [\u0438\u043B\u0438] \u043E\u0442\u0432\u0435\u0440\u0433\u0430\u0435\u043C\u043E\u0435 <em>(heya)</em>, \u0438 \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> [\u043A\u0430\u043A] \u0442\u0440\u0430\u0432\u0438\u043D\u043A\u0430 <em>(t\u1E5B\u1E47a)</em> \u0438 \u043A\u0430\u043A <em>(\u0101dikam)</em>, \u043B\u0438\u0441\u0442 <em>(par\u1E47am)</em>, \u043A\u0430\u043C\u0435\u043D\u044C <em>(p\u0101\u1E63\u0101\u1E47am)</em>, \u043D\u0430\u0440\u044F\u0434\u0443 \u0441 <em>(sa)</em> \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u044B\u043C\u0438 \u0438 \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u044B\u043C\u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(cara-acaram)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(\u0101di)</em> \u015Aiva --\u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 1-- <em>(\u015Biva)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F <em>(paryantam)</em> \u0437\u0435\u043C\u043B\u0435\u0439 --\u0442\u0430\u0442\u0442\u0432\u043E\u0439, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0435\u0439 36-- <em>(avani)</em>, \u0441\u043E\u043F\u0440\u043E\u0432\u043E\u0436\u0434\u0430\u0435\u043C\u044B\u043C\u0438 <em>(upab\u1E5B\u1E41hitam)</em> \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u044B\u043C\u0438 \u0438 \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u044B\u043C\u0438 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044F\u043C\u0438 <em>(bh\u0101va-abh\u0101va)</em>; [\u0438] \u043F\u043E\u0441\u043B\u0435 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 <em>(dhy\u0101tv\u0101)</em> \u043D\u0430 \u0432\u0441\u0435\u043C <em>(sarvam)</em>, \u043A\u0430\u043A \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(mayam)</em> \u0428\u0438\u0432\u0435 <em>(\u015Biva)</em>, \u043E\u043D \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 <em>(na pr\u0101pnuy\u0101t)</em> \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em> \u0441\u043D\u043E\u0432\u0430 <em>(bh\u016Byas... iti)</em>&quot;||</p></blockquote><p>[\u0418] \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>:</p><blockquote><p>&quot;\u041F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u043E\u0435 <em>(su)</em> \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(nirv\u0101\u1E47am)</em>, \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u043E\u0442 <em>(\u0101gatam)</em> \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 <em>(p\u0101rampara)</em> \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0445 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u043E\u0432 <em>(guru)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E <em>(param)</em> \u0447\u0438\u0441\u0442\u044B\u043C <em>(\u015Buddham)</em>. \u041E\u0431\u043B\u0430\u0434\u0430\u044F \u0437\u043D\u0430\u043D\u0438\u0435\u043C \u044D\u0442\u043E\u0433\u043E [\u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F] --\u0442.\u0435. \u0438\u0441\u043F\u044B\u0442\u0430\u0432 \u044D\u0442\u043E-- <em>(tad-viditv\u0101)</em> \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C [\u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438] <em>(vimucyeta)</em><sup>2</sup></p></blockquote><p>, [\u0438] \u043F\u043E\u0441\u043B\u0435 \u0441\u043C\u0435\u0440\u0442\u0438 <em>(gatv\u0101)</em> \u043E\u043D \u043D\u0435 \u0440\u043E\u0434\u0438\u0442\u0441\u044F <em>(na j\u0101yate)</em> \u0432\u043D\u043E\u0432\u044C <em>(bh\u016Byas... iti)</em><sup>3</sup>&quot;| [\u0421\u043C. IV, 240-241 \u0432 Svacchandatantra]</p><p>[\u042D\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E] <em>(api)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C M\u1E5Btyujit --Netratantra-- <em>(\u015Br\u012B-m\u1E5Btyujiti)</em>:</p><blockquote><p>&quot;\u041F\u0440\u043E\u0439\u0434\u044F <em>(d\u1E5B\u1E63\u1E6Dv\u0101)</em>, \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(divyena)</em> \u043F\u0443\u0442\u0435\u043C <em>(m\u0101rge\u1E47a)</em> \u0419\u043E\u0433\u0438 <em>(yoga)</em>, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 <em>(vinirmuktam)</em> \u043E\u0442 \u0442\u0440\u0435\u0445 \u0442\u0430\u0442\u0442\u0432, \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 <em>(tattva-traya)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E \u0432\u0435\u0447\u043D\u044B\u0439 <em>(\u015B\u0101\u015Bvatam tu)</em>, \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u044B\u0439 <em>(acalam)</em> [\u0438] \u043F\u0435\u0440\u043C\u0430\u043D\u0435\u043D\u0442\u043D\u044B\u0439 <em>(dhruvam)</em>, \u043E\u043D \u043D\u0435 \u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(na j\u0101yate)</em> \u0432\u043D\u043E\u0432\u044C <em>(bh\u016Byas... iti)</em><sup>4</sup>&quot;||<br> [\u0421\u043C. VIII, 26-27 \u0432 Netratantra]</p></blockquote><p>||18||</p><hr><ol><li><p>\u0425\u043E\u0442\u044F \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0438 \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F \u043A\u0430\u043A \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u0434\u043B\u044F \u0442\u0430\u043A\u043E\u0433\u043E \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u0434\u0440\u0443\u0433\u043E\u0433\u043E \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F. \u0420\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u0432\u0435\u0449\u0435\u0439 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0442\u0435\u043B\u043E, \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0438 \u043F\u0440.), \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E \u0431\u043E\u043B\u044C\u044E \u0438 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E \u0437\u0430\u043A\u043E\u043D\u0443 \u041A\u0430\u0440\u043C\u044B (\u0442.\u0435. \u0441\u043E\u0437\u0434\u0430\u0435\u0442\u0441\u044F \u0432\u0430\u0448\u0438\u043C\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C\u0438). \u041E\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u0441\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u0438\u043B\u0438 \u043F\u043E\u043C\u043E\u0449\u044C \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 M\u0101y\u012Byamala (\u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435, \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0435\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435) \u0438 K\u0101rmamala (\u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435, \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u043F\u0443\u0442\u0430\u043D\u0438\u0446\u0443 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u0438\u0440\u043E\u0434\u044B \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u0414\u0435\u043B\u0430\u0442\u0435\u043B\u044F). \u0412 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0442\u0435\u043B\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0435 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C Yog\u012B \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u0438\u0437 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 Icch\u0101\u015Bakti, \u0430 \u043D\u0435 \u0438\u0437 \u0437\u0430\u043A\u043E\u043D\u0430 \u041A\u0430\u0440\u043C\u044B, \u043F\u0435\u0440\u0435\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u043C \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0432\u0441\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435 \u044D\u0442\u0438\u043C\u0438 \u0442\u0435\u043B\u0430\u043C\u0438, \u043D\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0434\u043B\u044F \u043D\u0435\u0433\u043E \u043A\u0430\u0440\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0438 \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u043D\u0435 \u043F\u0440\u0438\u0432\u0435\u0434\u0443\u0442 \u043A \u0434\u0440\u0443\u0433\u043E\u043C\u0443 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044E.</p></li><li><p>\u041C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u0439 Svacchandoddyota: &quot; \u0935\u093F\u092E\u0941\u091A\u094D\u092F\u0924 \u0907\u0924\u093F \u091C\u0940\u0935\u0928\u094D\u0928\u0947\u0935 \u0935\u093F\u092E\u0941\u0915\u094D\u0924\u0903 \u0938\u094D\u092F\u093E\u0924\u094D&quot; - &quot;vimucyata iti j\u012Bvanneva vimukta\u1E25 sy\u0101t&quot; - &quot;&#39;vimucyate&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u043B\u0441\u044F \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438&quot;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u044F \u0434\u043E\u0431\u0430\u0432\u0438\u043B &quot;\u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438&quot; \u0432 \u0441\u0432\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E &quot;vimucyate&quot; \u043F\u0440\u044F\u043C\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C&quot;.</p></li><li><p>K\u1E63emar\u0101ja \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u044D\u0442\u0443 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044E\u044E \u0447\u0430\u0441\u0442\u044C \u0441\u0442\u0440\u043E\u0444\u044B \u0432 \u0441\u0432\u043E\u0435\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 Svacchandatantra: &quot;\u0917\u0924\u094D\u0935\u0947\u0924\u093F \u0926\u0947\u0939\u093E\u0928\u094D\u0924\u0947 \u0924\u0926\u0948\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u092E\u0947\u0924\u093F\u0965&quot; - &quot;gatveti deh\u0101nte tadaik\u0101tmyameti||&quot; - &quot;&#39;gatv\u0101&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u0432 \u043A\u043E\u043D\u0446\u0435 \u0442\u0435\u043B\u0430&#39; --\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u043D\u0430\u0441\u0442\u0443\u043F\u0438\u0442 \u0441\u043C\u0435\u0440\u0442\u044C--, [\u0432 \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442,] \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u0422\u0435\u043C --\u0441 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E, \u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043E\u043D \u043D\u0435 \u0440\u043E\u0434\u0438\u0442\u0441\u044F \u0432\u043D\u043E\u0432\u044C--&quot;. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0422\u0440\u0438\u043A\u0435 \u0438 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0443 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u0445 \u0441\u0438\u0441\u0442\u0435\u043C \u0418\u043D\u0434\u0438\u0438, \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F. \u041A\u0430\u0436\u0434\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430, \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E, \u043F\u043E\u0441\u0442\u0443\u043B\u0438\u0440\u0443\u0435\u0442 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E-\u0440\u0430\u0437\u043D\u043E\u043C\u0443. \u0412 \u0422\u0440\u0438\u043A\u0435, \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435, \u0447\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u0434\u0440\u0443\u0433\u043E\u0435 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u0438.</p></li><li><p>\u041C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u0439 Netroddyota \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0432\u0435\u0449\u0435\u0439 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u0432\u044B\u043C\u0438 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043C\u0438 \u0438 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044F\u043C\u0438 \u0432 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 Netratantra:</p></li><li><p>&quot; \u0926\u0943\u0937\u094D\u091F\u094D\u0935\u093E \u0938\u093E\u0915\u094D\u0937\u093E\u0924\u094D\u0915\u0943\u0924\u094D\u092F&quot; - &quot;d\u1E5B\u1E63\u1E6Dv\u0101 s\u0101k\u1E63\u0101tk\u1E5Btya&quot; - &quot;\u041F\u043E\u0441\u043B\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u044F, \u0442.\u0435. \u043F\u043E\u0441\u043B\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F&quot;;</p></li><li><p>&quot; \u0926\u093F\u0935\u094D\u092F\u0947\u0928 \u092F\u094B\u0917\u092E\u093E\u0930\u094D\u0917\u0947\u0923 \u0935\u093F\u0915\u0932\u094D\u092A\u0939\u093E\u0928\u094B\u0928\u094D\u092E\u093F\u0937\u0926\u0935\u093F\u0915\u0932\u094D\u092A\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u094B\u092A\u093E\u092F\u0947\u0928&quot; - &quot;divyena yogam\u0101rge\u1E47a vikalpah\u0101nonmi\u1E63adavikalpavimar\u015B\u0101va\u1E63\u1E6Dambhop\u0101yena&quot; - &quot;\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043F\u0443\u0442\u0435\u043C \u0419\u043E\u0433\u0438, \u0442.\u0435. \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430, \u0438\u043B\u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043D\u0430 avikalpavimar\u015Ba, \u0438\u043B\u0438 &#39;\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u043C \u043C\u044B\u0441\u043B\u0435\u0439&#39; , \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u0438\u044F\u0435\u0442 \u0441 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435\u043C \u043C\u044B\u0441\u043B\u0435\u0439&quot;;</p></li><li><p>&quot;\u0924\u0924\u094D\u0924\u094D\u0935\u0924\u094D\u0930\u092F\u0902 \u0928\u0930\u0936\u0915\u094D\u0924\u093F\u0936\u093F\u0935\u093E\u0916\u094D\u092F\u092E\u094D\u0964&quot; - &quot;Tattvatraya\u1E41 nara\u015Bakti\u015Biv\u0101khyam|&quot; - &quot;\u0422\u0440\u0438 \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0435 \u043A\u0430\u043A nara (\u0447\u0435\u043B\u043E\u0432\u0435\u043A), \u015Aakti \u0438 \u015Aiva&quot;, \u0433\u0434\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0435 \u0434\u0432\u0430 \u0435\u0441\u0442\u044C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0422\u043E\u0433\u043E (Parama\u015Biva), \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D \u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0442\u0440\u043E\u0439\u043D\u043E\u0433\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F, \u043A\u043E\u0440\u043E\u0447\u0435, \u042D\u0442\u043E \u0434\u0430\u0436\u0435 \u043D\u0435 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0438 \u0415\u0433\u043E \u0421\u0438\u043B\u0430, \u043D\u0435 \u0433\u043E\u0432\u043E\u0440\u044F \u0443\u0436\u0435 \u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435 (\u0437\u0430\u0433\u0430\u0434\u043E\u0447\u043D\u0430\u044F \u0442\u0435\u043C\u0430, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0437\u0434\u0435\u0441\u044C \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C);</p></li><li><p>&quot;\u0905\u091A\u0932\u092E\u092A\u0930\u093F\u0923\u093E\u092E\u093F&quot; - &quot;acalamapari\u1E47\u0101mi&quot; - &quot;acala, \u0442.\u0435. \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u044B\u0439&quot;; \u0438 \u043D\u0430\u043A\u043E\u043D\u0435\u0446</p></li><li><p>&quot;\u0927\u094D\u0930\u0941\u0935\u0902 \u0928\u093F\u0924\u094D\u092F\u092E\u094D&quot; - &quot;dhruva\u1E41 nityam&quot; - &quot;dhruva, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u0435\u0440\u043C\u0430\u043D\u0435\u043D\u0442\u043D\u044B\u0439&quot;.</p></li></ol></div>',2),p=[i];function u(r,v,s,n,y,d){return m(),e("div",null,p)}var h=a(o,[["render",u]]);export{q as __pageData,h as default};
